const workflows = $input.all();
const active = workflows.filter(w => w.active);
const total = workflows.length;

const snapshot = {
  total_workflows: total,
  active_workflows: active.length,
  total_executions_24h: workflows.reduce((a, w) => a + (w.executions_24h || 0), 0),
  total_success_24h: workflows.reduce((a, w) => a + (w.success_24h || 0), 0),
  total_error_24h: workflows.reduce((a, w) => a + (w.error_24h || 0), 0),
  overall_success_rate: null,
  avg_execution_time_ms: null,
  snapshot_at: new Date().toISOString()
};

const totalExec = snapshot.total_success_24h + snapshot.total_error_24h;
if (totalExec > 0) {
  snapshot.overall_success_rate = snapshot.total_success_24h / totalExec;
}

const durations = workflows.filter(w => w.avg_execution_ms).map(w => w.avg_execution_ms);
if (durations.length) {
  snapshot.avg_execution_time_ms = Math.round(durations.reduce((a,b) => a + b, 0) / durations.length);
}

return [{ json: snapshot }];
